"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[6897],{1554:a=>{a.exports=JSON.parse('{"lang":"pl","resources":{"landing":{"meta":{"title":"Linguist \u2013 Prywatne t\u0142umaczenie stron internetowych | T\u0142umacz w przegl\u0105darce dla Chrome i Firefox","description":"Rozszerzenie do Chrome i Firefox, kt\xf3re stawia prywatno\u015b\u0107 na pierwszym miejscu. B\u0142yskawicznie t\u0142umacz strony internetowe, zaznaczony tekst, napisy i wiadomo\u015bci. Dzia\u0142a offline i obs\u0142uguje integracje z zewn\u0119trznymi t\u0142umaczami oraz API."},"navigation":{"features":{"content":"Funkcje"},"blog":{"content":"Blog"},"docs":{"content":"Dokumentacja"},"github":{"content":"GitHub"}},"install":{"chrome":"Zainstaluj dla Chrome","firefox":"Zainstaluj dla Firefox"},"sections":{"hero":{"title":"P\u0142ynne t\u0142umaczenie stron internetowych","description":"Linguist to wszechstronny t\u0142umacz w przegl\u0105darce, korzystaj\u0105cy z najpopularniejszych us\u0142ug t\u0142umaczeniowych.\\n\\nT\u0142umacz ca\u0142e strony internetowe, zaznaczony tekst, napisy na Netflixie lub podczas wideorozm\xf3w, a tak\u017ce prywatne wiadomo\u015bci. Ods\u0142uchuj t\u0142umaczenia i dodawaj wa\u017cne poj\u0119cia do osobistego s\u0142ownika, aby uczy\u0107 si\u0119 nowych s\u0142\xf3w, r\xf3wnie\u017c offline.\\n\\nLinguist to nowoczesna alternatywa dla rozszerzenia T\u0142umacz Google, kt\xf3ra chroni Twoj\u0105 prywatno\u015b\u0107. Wypr\xf3buj bezp\u0142atnie."},"opensource":{"title":"Otwarte oprogramowanie","content":"Linguist to bezp\u0142atne rozszerzenie do t\u0142umaczenia o <0>otwartym kodzie \u017ar\xf3d\u0142owym</0>. Nie gromadzi ani nie sprzedaje danych u\u017cytkownik\xf3w.\\n\\nMo\u017cesz <1>przekaza\u0107 darowizn\u0119</1>, aby wesprze\u0107 Linguist i pom\xf3c nam utrzyma\u0107 niezale\u017cno\u015b\u0107 oraz wysok\u0105 jako\u015b\u0107.\\n\\nUdost\u0119pnij Linguist w mediach spo\u0142eczno\u015bciowych, aby pom\xf3c innym go odkry\u0107."},"support":{"title":"Wsparcie","content":"Je\u015bli masz pytania, skontaktuj si\u0119 z nami <0/>.\\nJe\u015bli zauwa\u017cysz b\u0142\u0105d i masz konto na GitHubie, <1>zg\u0142o\u015b problem</1>."},"createdBy":{"content":"Stworzone przez <0/>."}},"features":{"title":"Funkcje","items":{"offlineTranslation":{"title":"T\u0142umaczenie offline i prywatno\u015b\u0107","content":"T\u0142umacz tekst bezpo\u015brednio na swoim urz\u0105dzeniu dzi\u0119ki wbudowanemu t\u0142umaczowi offline. Tw\xf3j tekst pozostaje prywatny i nie jest wysy\u0142any przez internet.\\n\\nW\u0142\u0105cz t\u0119 funkcj\u0119 w ustawieniach, aby zachowa\u0107 prywatno\u015b\u0107 t\u0142umacze\u0144 podczas pracy z e-mailami, dokumentami lub prywatnymi wiadomo\u015bciami.\\n\\nT\u0142umacz offline pozwala r\xf3wnie\u017c na t\u0142umaczenie stron bez po\u0142\u0105czenia z internetem, co jest szczeg\xf3lnie przydatne w podr\xf3\u017cy."},"fullPageTranslation":{"title":"T\u0142umaczenie ca\u0142ych stron internetowych","content":"Szybkie t\u0142umaczenie ca\u0142ych stron w wysokiej jako\u015bci za pomoc\u0105 zaledwie kilku klikni\u0119\u0107.\\n\\nU\u017cyj skr\xf3tu klawiszowego, aby t\u0142umaczy\u0107 b\u0142yskawicznie. Najed\u017a kursorem na przet\u0142umaczony tekst, aby zobaczy\u0107 orygina\u0142. T\u0142umacz nawet prywatne strony ukryte za formularzami logowania lub paywallami.\\n\\nSkonfiguruj regu\u0142y automatycznego t\u0142umaczenia na podstawie j\u0119zyka strony lub domeny.\\n\\nLinguist ingeruje w struktur\u0119 strony w minimalnym stopniu: zmienia tylko fragmenty tekstowe, zachowuj\u0105c oryginalny uk\u0142ad i wygod\u0119 przegl\u0105dania.\\n\\nW\u0142\u0105cz t\u0142umaczenie w czasie rzeczywistym podczas mi\u0119dzynarodowych spotka\u0144 na Zoomie, Google Meet i Microsoft Teams."},"selectedTextTranslation":{"title":"T\u0142umaczenie zaznaczonego tekstu na dowolnej stronie","content":"Trafiasz na nieznane s\u0142owa podczas czytania artyku\u0142u w sieci?\\nPo prostu zaznacz tekst na stronie i kliknij przycisk t\u0142umaczenia.\\n\\nPos\u0142uchaj zar\xf3wno oryginalnego, jak i przet\u0142umaczonego tekstu, a nast\u0119pnie zapisz t\u0142umaczenia w swoim s\u0142owniku, aby wr\xf3ci\u0107 do nich p\xf3\u017aniej."},"textTranslation":{"title":"Szybkie t\u0142umaczenie tekstu","content":"Potrzebujesz co\u015b szybko przet\u0142umaczy\u0107? Kliknij ikon\u0119 Linguist i wpisz sw\xf3j tekst.\\n\\nNie musisz prze\u0142\u0105cza\u0107 si\u0119 mi\u0119dzy kartami ani otwiera\u0107 stron z t\u0142umaczami. T\u0142umacz bezpo\u015brednio w przegl\u0105darce, korzystaj\u0105c z wybranej przez siebie us\u0142ugi."},"knowledgeBase":{"title":"Budowanie osobistej bazy wiedzy","content":"Ka\u017cde t\u0142umaczenie jest zapisywane w historii, a wa\u017cne poj\u0119cia mo\u017cesz dodawa\u0107 do osobistego s\u0142ownika. W dowolnej chwili przeszukuj sw\xf3j s\u0142ownik i histori\u0119 t\u0142umacze\u0144.\\n\\nNic nie zginie, nawet podczas d\u0142ugich poszukiwa\u0144 informacji czy nauki.\\n\\nS\u0142ownik dzia\u0142a offline, co czyni Linguist idealnym narz\u0119dziem dla os\xf3b ucz\u0105cych si\u0119 j\u0119zyk\xf3w i podr\xf3\u017cnik\xf3w, kt\xf3rzy potrzebuj\u0105 sta\u0142ego dost\u0119pu do swoich list s\u0142\xf3wek."},"customTranslators":{"title":"Integracja us\u0142ug t\u0142umaczeniowych i API","content":"Linguist pozwala Ci wybra\u0107, z kt\xf3rej us\u0142ugi t\u0142umaczeniowej chcesz korzysta\u0107.\\n\\nObs\u0142uguje popularnych dostawc\xf3w, takich jak Google, Yandex i Microsoft, oferuj\u0105c dost\u0119p do ponad 100 j\u0119zyk\xf3w.\\n\\nJe\u015bli brakuje us\u0142ugi, kt\xf3rej potrzebujesz, mo\u017cesz doda\u0107 j\u0105 jako <0>w\u0142asnego t\u0142umacza</0>.\\n\\nW\u0142asne t\u0142umacze pozwalaj\u0105 na integracj\u0119 dowolnego systemu t\u0142umaczeniowego \u2014 od nowoczesnych us\u0142ug opartych na modelach j\u0119zykowych (LLM), takich jak ChatGPT, DeepL, DeepSeek i Gemini, po lokalne translatory dzia\u0142aj\u0105ce na Twoim urz\u0105dzeniu, takie jak Ollama czy LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"Czym jest Linguist?","content":"Linguist to rozszerzenie do t\u0142umaczenia dla Chrome i Firefox, kt\xf3re stawia prywatno\u015b\u0107 na pierwszym miejscu.\\n\\nPozwala t\u0142umaczy\u0107 ca\u0142e strony internetowe, zaznaczony tekst, napisy i wiadomo\u015bci bezpo\u015brednio w przegl\u0105darce, bez konieczno\u015bci przechodzenia na zewn\u0119trzne strony t\u0142umaczy."},"whyLinguist":{"title":"Dlaczego warto korzysta\u0107 z Linguist?","content":"Istnieje wiele rozszerze\u0144 do t\u0142umaczenia stron, a niekt\xf3re przegl\u0105darki maj\u0105 nawet wbudowane translatory. Dlaczego wi\u0119c warto wybra\u0107 Linguist?\\n\\nWi\u0119kszo\u015b\u0107 wbudowanych t\u0142umaczy i rozszerze\u0144 jest ma\u0142o elastyczna. Wiele z nich opiera si\u0119 na jednym dostawcy, takim jak T\u0142umacz Google czy Microsoft Bing, podczas gdy Firefox oferuje w\u0142asnego t\u0142umacza offline. W wi\u0119kszo\u015bci przypadk\xf3w nie masz mo\u017cliwo\u015bci wyboru us\u0142ugi, kt\xf3ra najlepiej odpowiada Twoim potrzebom.\\n\\nJe\u015bli jako\u015b\u0107 t\u0142umaczenia nie jest wystarczaj\u0105ca do Twoich cel\xf3w lub je\u015bli wysy\u0142anie prywatnych tekst\xf3w do zewn\u0119trznych us\u0142ug jest dla Ciebie nie do przyj\u0119cia, wiele narz\u0119dzi nie oferuje \u017cadnej dobrej alternatywy.\\n\\nPonadto wiele narz\u0119dzi skupia si\u0119 tylko na jednym zadaniu. Niekt\xf3re t\u0142umacz\u0105 ca\u0142e strony, podczas gdy inne tylko zaznaczony tekst.\\n\\nJednocze\u015bnie niekt\xf3re rozszerzenia s\u0105 tworzone g\u0142\xf3wnie z my\u015bl\u0105 o zarabianiu. Funkcje takie jak historia t\u0142umacze\u0144 czy osobiste s\u0142owniki mog\u0105 wymaga\u0107 subskrypcji, a czasem nawet podstawowe opcje, jak ciemny motyw, s\u0105 traktowane jako funkcje premium.\\n\\nLinguist przyjmuje inne podej\u015bcie. Zosta\u0142 zaprojektowany jako praktyczne narz\u0119dzie do t\u0142umaczenia. Mo\u017cesz wybra\u0107 us\u0142ug\u0119, kt\xf3ra sprawdza si\u0119 u Ciebie najlepiej, prze\u0142\u0105cza\u0107 si\u0119 mi\u0119dzy dostawcami lub dodawa\u0107 w\u0142asne, niestandardowe translatory.\\n\\nLinguist \u0142\u0105czy r\xf3wnie\u017c wszystko w jednym miejscu: t\u0142umacz ca\u0142e strony internetowe, zaznaczony tekst, napisy i wiadomo\u015bci, zachowuj\u0105c jednocze\u015bnie wa\u017cne t\u0142umaczenia w historii i osobistym s\u0142owniku."},"theLinguistLogo":{"title":"Dlaczego w logo Linguist znajduje si\u0119 Wie\u017ca Babel?","content":"Logo Linguist jest inspirowane <wiki>Wie\u017c\u0105 Babel</wiki>, jedn\u0105 z najstarszych opowie\u015bci o j\u0119zyku i komunikacji.\\n\\nWed\u0142ug tej historii ludzie m\xf3wili kiedy\u015b jednym j\u0119zykiem i pr\xf3bowali zbudowa\u0107 wie\u017c\u0119 si\u0119gaj\u0105c\u0105 nieba. Budowla nigdy nie zosta\u0142a uko\u0144czona, a ludzko\u015b\u0107 rozproszy\u0142a si\u0119, tworz\u0105c wiele r\xf3\u017cnych j\u0119zyk\xf3w. Od tego czasu r\xf3\u017cnice j\u0119zykowe cz\u0119sto utrudnia\u0142y komunikacj\u0119.\\n\\nLinguist powsta\u0142, aby pom\xf3c rozwi\u0105za\u0107 ten problem.\\n\\nWie\u017ca Babel w logo jest przypomnieniem tej historii: wielu j\u0119zyk\xf3w, wielu kultur i nieustannego ludzkiego wysi\u0142ku, by si\u0119 nawzajem zrozumie\u0107. Linguist pomaga pokonywa\u0107 te bariery, czyni\u0105c t\u0142umaczenie prostym, elastycznym i dost\u0119pnym bezpo\u015brednio w przegl\u0105darce.\\n\\nLogo odzwierciedla r\xf3wnie\u017c ducha projektu. Linguist to nie tylko kolejna nak\u0142adka na \u201eT\u0142umacza Google\u201d. Tworz\u0105 go ludzie, kt\xf3rym zale\u017cy na j\u0119zykach, prywatno\u015bci i otwartych technologiach. Wie\u017ca Babel symbolizuje ciekawo\u015b\u0107, nauk\u0119 i ide\u0119, \u017ce r\xf3\u017cnice j\u0119zykowe powinny zbli\u017ca\u0107 ludzi, a nie ich dzieli\u0107."},"imageTranslation":{"title":"Dlaczego Linguist nie t\u0142umaczy tekstu na obrazach?","content":"Linguist skupia si\u0119 na niezawodnych funkcjach t\u0142umaczeniowych wysokiej jako\u015bci.\\n\\nZbadali\u015bmy r\xf3\u017cne podej\u015bcia do t\u0142umaczenia tekstu znajduj\u0105cego si\u0119 na obrazach. Obecnie wi\u0119kszo\u015b\u0107 dost\u0119pnych rozwi\u0105za\u0144 nie zapewnia sp\xf3jnych wynik\xf3w, zw\u0142aszcza gdy dzia\u0142aj\u0105 bezpo\u015brednio w przegl\u0105darce \u2014 co jest kluczowe dla zachowania prywatno\u015bci u\u017cytkownik\xf3w.\\n\\nZ tego powodu Linguist nie oferuje obecnie t\u0142umaczenia obraz\xf3w. Wolimy nie udost\u0119pnia\u0107 funkcji, kt\xf3re nie spe\u0142niaj\u0105 naszych standard\xf3w jako\u015bci.\\n\\nJe\u015bli w przysz\u0142o\u015bci znajdziemy niezawodny i szanuj\u0105cy prywatno\u015b\u0107 spos\xf3b na wdro\u017cenie t\u0142umaczenia obraz\xf3w, z przyjemno\u015bci\u0105 go dodamy."},"howTranslatePages":{"title":"Jak Linguist t\u0142umaczy strony internetowe?","content":"Linguist potrafi przet\u0142umaczy\u0107 ca\u0142e strony internetowe za pomoc\u0105 zaledwie kilku klikni\u0119\u0107. Mo\u017cesz rozpocz\u0105\u0107 t\u0142umaczenie strony, u\u017cywaj\u0105c przycisku rozszerzenia lub skr\xf3tu klawiszowego.\\n\\nOryginalny tekst zawsze pozostaje dost\u0119pny. Najed\u017a kursorem na przet\u0142umaczony fragment, aby zobaczy\u0107 orygina\u0142."},"offlineTranslation":{"title":"Czy Linguist potrafi t\u0142umaczy\u0107 strony offline?","content":"Tak. Linguist zawiera wbudowanego t\u0142umacza offline, kt\xf3ry pozwala na t\u0142umaczenie tekstu bez wysy\u0142ania danych przez internet.\\n\\nPomaga to chroni\u0107 Twoj\u0105 prywatno\u015b\u0107 i umo\u017cliwia t\u0142umaczenie tre\u015bci nawet bez po\u0142\u0105czenia z sieci\u0105."},"privacy":{"title":"Czy Linguist dba o prywatno\u015b\u0107?","content":"Tak. Linguist zosta\u0142 zaprojektowany z my\u015bl\u0105 o prywatno\u015bci.\\n\\nRozszerzenie nie gromadzi ani nie sprzedaje danych u\u017cytkownik\xf3w. Podczas korzystania z <offline-translator>t\u0142umacza offline</offline-translator>, t\u0142umaczenia s\u0105 przetwarzane w ca\u0142o\u015bci na Twoim urz\u0105dzeniu."},"supportedBrowsers":{"title":"Jakie przegl\u0105darki obs\u0142uguje Linguist?","content":"Linguist jest dost\u0119pny dla Chrome i Firefox. Dzia\u0142a r\xf3wnie\u017c w innych przegl\u0105darkach opartych na silniku Chromium, kt\xf3re obs\u0142uguj\u0105 rozszerzenia z Chrome.\\n\\nLinguist dzia\u0142a tak\u017ce w przegl\u0105darkach na Androida obs\u0142uguj\u0105cych rozszerzenia, takich jak Firefox dla Androida oraz niekt\xf3rych przegl\u0105darkach opartych na Chromium."},"selectedText":{"title":"Czy Linguist potrafi t\u0142umaczy\u0107 zaznaczony tekst?","content":"Tak. Po prostu zaznacz tekst na dowolnej stronie internetowej i u\u017cyj przycisku t\u0142umaczenia, aby przet\u0142umaczy\u0107 go b\u0142yskawicznie.\\n\\nMo\u017cesz r\xf3wnie\u017c ods\u0142ucha\u0107 t\u0142umaczenie i zapisa\u0107 je w swoim osobistym s\u0142owniku."},"customTranslators":{"title":"Czy mog\u0119 u\u017cywa\u0107 w\u0142asnej us\u0142ugi t\u0142umaczeniowej?","content":"Tak. Linguist obs\u0142uguje <custom-translator>w\u0142asne t\u0142umacze</custom-translator>, co pozwala na integracj\u0119 dodatkowych us\u0142ug t\u0142umaczeniowych.\\n\\nMo\u017cesz pod\u0142\u0105czy\u0107 zewn\u0119trzne API lub lokalne systemy t\u0142umaczeniowe, takie jak <libre-translate>LibreTranslate</libre-translate> czy <ollama>Ollama</ollama>."},"isFree":{"title":"Czy Linguist jest darmowy?","content":"Tak. Linguist jest ca\u0142kowicie bezp\u0142atny i udost\u0119pniany jako <linguist>otwarte oprogramowanie (open source)</linguist>.\\n\\nProjekt rozwija si\u0119 dzi\u0119ki wsparciu spo\u0142eczno\u015bci, a Ty mo\u017cesz opcjonalnie <donations>wesprze\u0107 go darowizn\u0105</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bg","langName":"\u0431\u044a\u043b\u0433\u0430\u0440\u0441\u043a\u0438","url":"https://linguister.io/bg"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"ca","langName":"catal\xe0","url":"https://linguister.io/ca"},{"langCode":"cs","langName":"\u010de\u0161tina","url":"https://linguister.io/cs"},{"langCode":"da","langName":"dansk","url":"https://linguister.io/da"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"el","langName":"\u0395\u03bb\u03bb\u03b7\u03bd\u03b9\u03ba\u03ac","url":"https://linguister.io/el"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fa","langName":"\u0641\u0627\u0631\u0633\u06cc","url":"https://linguister.io/fa"},{"langCode":"fi","langName":"suomi","url":"https://linguister.io/fi"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"he","langName":"\u05e2\u05d1\u05e8\u05d9\u05ea","url":"https://linguister.io/he"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"hu","langName":"magyar","url":"https://linguister.io/hu"},{"langCode":"id","langName":"Indonesia","url":"https://linguister.io/id"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ka","langName":"\u10e5\u10d0\u10e0\u10d7\u10e3\u10da\u10d8","url":"https://linguister.io/ka"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"nb","langName":"norsk bokm\xe5l","url":"https://linguister.io/nb"},{"langCode":"nl","langName":"Nederlands","url":"https://linguister.io/nl"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pl","langName":"polski","url":"https://linguister.io/pl"},{"langCode":"pt-BR","langName":"portugu\xeas (Brasil)","url":"https://linguister.io/pt-BR"},{"langCode":"pt-PT","langName":"portugu\xeas europeu","url":"https://linguister.io/pt-PT"},{"langCode":"ro","langName":"rom\xe2n\u0103","url":"https://linguister.io/ro"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"sl","langName":"sloven\u0161\u010dina","url":"https://linguister.io/sl"},{"langCode":"sr","langName":"\u0441\u0440\u043f\u0441\u043a\u0438","url":"https://linguister.io/sr"},{"langCode":"sv","langName":"svenska","url":"https://linguister.io/sv"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"te","langName":"\u0c24\u0c46\u0c32\u0c41\u0c17\u0c41","url":"https://linguister.io/te"},{"langCode":"th","langName":"\u0e44\u0e17\u0e22","url":"https://linguister.io/th"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"uk","langName":"\u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0430","url":"https://linguister.io/uk"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh-CN","langName":"\u4e2d\u6587\uff08\u4e2d\u56fd\uff09","url":"https://linguister.io/zh-CN"},{"langCode":"zh-TW","langName":"\u4e2d\u6587\uff08\u53f0\u7063\uff09","url":"https://linguister.io/zh-TW"}]}')}}]);